var loaded = false, translation = {};

(async () => {
  try {
    const lang = localStorage.getItem("lang");
    
    if (!lang) {
      window.location.href = "lang.html";
      return;
    }

    // Handle default language
    if (lang !== "en_us") {
      const cache = await caches.open("translation_cache");
      const cacheKey = `./lang/${lang}.json`;
      
      let cachedResponse = await cache.match(cacheKey);
      
      if (cachedResponse) {
        translation = await cachedResponse.json();
      } else {
        const fetchResponse = await fetch(cacheKey);
        translation = await fetchResponse.json();
        // Cache the fetched translation
        await cache.put(cacheKey, fetchResponse.clone());
      }
    }

    // Apply translations
    applyTranslations();
    loaded = true;

    // Start observing after initial load
    startObserver();

  } catch (error) {
    console.error("Translation failed:", error);
  }
})();

function applyTranslations() {
  const elements = document.querySelectorAll("h1, h2, h3, h4, h5, h6, p, span, a, button, option");
  
  elements.forEach(el => {
    // Skip elements that are already translated (add data attribute)
    if (el.hasAttribute('data-translated')) return;
    
    const original = el.innerText.trim();
    if (!original) return;
    
    if (translation[original]) {
      console.info("Translating:", original, "->", translation[original]);
      el.innerText = translation[original];
      el.setAttribute('data-translated', 'true');
      el.setAttribute('data-original', original);
    } else if (original !== "") {
      console.warn("No translation found for:", original);
    }
  });
}

function startObserver() {
  const observer = new MutationObserver(mutations => {
    let needsTranslation = false;
    
    mutations.forEach(mutation => {
      if (mutation.type === "childList" && mutation.addedNodes.length > 0) {
        // Check if added nodes contain translatable elements
        mutation.addedNodes.forEach(node => {
          if (node.nodeType === Node.ELEMENT_NODE) {
            if (node.matches && node.matches("h1, h2, h3, h4, h5, h6, p, span, a, button, option")) {
              needsTranslation = true;
            } else if (node.querySelectorAll) {
              if (node.querySelectorAll("h1, h2, h3, h4, h5, h6, p, span, a, button, option").length > 0) {
                needsTranslation = true;
              }
            }
          }
        });
      }
    });
    
    if (needsTranslation && loaded) {
      applyTranslations();
    }
  });
  
  observer.observe(document.body, {
    childList: true,
    subtree: true
  });
}